import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productStrings } from '../../../../config';
import { FormControl, InputLabel, Select, MenuItem, TableRow, TableCell, IconButton } from '@material-ui/core';
import { Delete } from '@material-ui/icons';


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5
    }
})
class _DescriptionRow extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedOptionId : null,
            selectedOptionValueId : null
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    onChange = e => {
        const value = e.target.value;
        this.setState({selectedOptionId : value});
    }
    onChangeValue(e){
        const value = e.target.value;
        this.setState({selectedOptionValueId : value});
    }
    render() {
        const {selectedOptionId, selectedOptionValueId} = this.state;
        const {classes,
            [productStrings.productDescriptions] : descriptions,
            descriptionId,
        } = this.props;
        let options = [];
        let optionsNames = [];
        if(descriptions && descriptionId){
            const {item : descriptionItem} = descriptions.getFirstObjectByPropValue("_id", descriptionId);
            if(descriptionItem) options = descriptionItem.options;
        }
        if(options) for (let i = 0; i < options.length; i++) {
            const item = options[i];
            optionsNames.push({_id : item._id, name : item.name});  
        } 
        let optionsValues = [];
        if(selectedOptionId){
            const {item : optionItem} = options.getFirstObjectByPropValue("_id", selectedOptionId);
            if(optionItem) {
                optionsValues = optionItem.values;
            }
        }
        return (
            <TableRow className={classes.root}>
                <TableCell className={classes.cell}>
                    <FormControl
                        style={{width : "100%"}}
                    >
                        <InputLabel htmlFor="names">Option Name</InputLabel>
                        <Select
                            value={selectedOptionId || ""}
                            onChange={this.onChange.bind(this)}
                            inputProps={{
                                id : "names",
                                style : {width : "100%"}
                            }}>
                            {optionsNames && optionsNames.map((item, index)=>{

                                return <MenuItem value={item._id} key={index}>{item.name}</MenuItem>
                            })}
                        </Select>
                    </FormControl>
                </TableCell>
                <TableCell className={classes.cell}>
                    <FormControl                    
                        style={{width : "100%"}}
                    >
                        <InputLabel htmlFor="values">Values</InputLabel>
                        <Select
                            value={selectedOptionValueId || ""}
                            onChange={this.onChangeValue.bind(this)}
                            inputProps={{
                                id : "values",
                                style : {width : "100%"}
                            }}>
                            {optionsValues && optionsValues.map((item, index)=>{

                                return <MenuItem key={index} value={item._id}>{item.name}</MenuItem>
                            })}
                        </Select>
                    </FormControl>
                </TableCell>
                <TableCell style={{width : 20}} className={classes.cell}>
                    <IconButton onClick={()=>this.props.deleteRow()}>
                        <Delete color="secondary"/>
                    </IconButton>
                </TableCell>
            </TableRow>
        );
    }
}


_DescriptionRow.propTypes = {
    classes : PropTypes.object.isRequired,
    descriptionId : PropTypes.number.isRequired,
    selectedOptions : PropTypes.array,
    descriptionId : PropTypes.number,
    getContext : PropTypes.func,
    deleteRow : PropTypes.func,
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.productDescriptions] : productReducer[productStrings.productDescriptions]
})


export const DescriptionRow = connect(mapStateToProps)(withStyles(style)(_DescriptionRow));
export {DescriptionRow as default}