import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails, Chip, Button, FormLabel, FormControl, TextField } from '@material-ui/core';
import { MyTable, EditableCellMapFormat, MyDialog } from '../../../../../includes';
import { colors } from '../../../../../../utils';
import { appActions, alertAction } from '../../../../../../actions';
import { OptionNameEdit } from './OptionNameEdit';
import { VariantOptionValueBox } from './VariantOptionValueBox';

const style = theme => ({
    root: {
    }
})

class _ItemVariants extends Component {
    constructor(props) {
        super(props);
        this.state = {
            variantUnusuable : null,
            variants : null,
            newVariantName : "",
            newVariantDialog : false,
        }
        this.optionNameContexts = {};
        this.optionValueContexts = {}
    }
    static getDerivedStateFromProps(props, state) {
        const { variants }= props;
        if(!state.variantUnusuable && variants){
            state.variants = state.variantUnusuable = variants
        }else if(JSON.stringify(state.variantUnusuable) !==
        JSON.stringify(variants)){
            state.variants = state.variantUnusuable = variants;
        }
        return state;
    }
    getOptionNameContexts = (variantIndex, optionId, isNew) => (context) => {
        if(!isNew){
            if(this.optionNameContexts[variantIndex]){
                this.optionNameContexts[variantIndex] = { [optionId] : context};
            }else this.optionNameContexts = {
                [variantIndex] : {
                    [optionId] : context
                }
            };
        }else {
            if(this.optionNameContexts[variantIndex])
                this.optionNameContexts[variantIndex].new = context;
            else this.optionNameContexts = {
                [variantIndex] : {
                    new : context
                }
            }
        }
    }
    getOptionValueContext = (variantIndex, optionId, isNew) => context => {
        if(!isNew){
            if(this.optionValueContexts[variantIndex]){
                this.optionValueContexts[variantIndex] = { [optionId] : context};
            }else this.optionValueContexts = {
                [variantIndex] : {
                    [optionId] : context
                }
            };
        }else {
            if(this.optionValueContexts[variantIndex])
                this.optionValueContexts[variantIndex].new = context;
            else this.optionValueContexts = {
                [variantIndex] : {
                    new : context
                }
            }
        }
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView = (variantIndex) => (editMode, {row, cellMap}) => {
        const {classes} = this.props;
        if(editMode){
            const optionType = row._id ? "_id" : "id";
            switch(cellMap){
                case "name" : 
                    return <OptionNameEdit
                            data={row[cellMap]}
                            getContext={this.getOptionNameContexts(variantIndex, row[optionType], row.new)}/>
                case "values" :
                    return <VariantOptionValueBox
                                row={row}
                                cellMap={cellMap}
                                getContext={this.getOptionValueContext(variantIndex, row[optionType], row.new)}
                                />
                    
            }
        }else{
            switch(cellMap){
                case "name" : return row[cellMap];
                case "values" : return <Fragment>
                    {row[cellMap] && row[cellMap].map((item, index)=>{
    
                        return <Chip key={index} label={item.name}/>
                    })}
                </Fragment>
            }
        }
    }
    editBtnHandler = (variantIndex) => row => () => {
        let variants = [...this.state.variants];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            variants[variantIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            variants[variantIndex].options[optionIndex].editing = true;
        }
        this.setState({variants});
    }
    cancelEditBtnHandler = (variantIndex) => row => () =>{
        let variants = [...this.state.variants];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            variants[variantIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            delete variants[variantIndex].options[optionIndex].editing;
        }
        this.setState({variants});
    }
    deleteBtnHandler = (variantIndex) => row => () => {
        let variants = [...this.state.variants];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            variants[variantIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            delete variants[variantIndex].options.splice(optionIndex, 1);
        }
        this.setState({variants});
    }
    addButtonHandler = (variantIndex) => length => () => {
        const {dispatch} = this.props;
        let optionName;
        if(this.optionNameContexts[variantIndex] &&
        this.optionNameContexts[variantIndex].new &&
        this.optionNameContexts[variantIndex].new.state.data !== ""){
            optionName = this.optionNameContexts[variantIndex].new.state.data;
        }else{
            appActions.showSnackbar(
                alertAction.error("option name is missing")
            )(dispatch);
            return;
        }
        let optionValues;
        if(this.optionValueContexts[variantIndex] &&
        this.optionValueContexts[variantIndex].new &&
        this.optionValueContexts[variantIndex].new.state.list){
            optionValues = this.optionValueContexts[variantIndex].new.state.list;
        }else{
            appActions.showSnackbar(
                alertAction.error("There is no values for the option")
            )(dispatch);
            return;
        }
        let {variants} = this.state;
        variants = variants ? [...variants] : [];
        if(variants[variantIndex] && 
            variants[variantIndex].options &&
            variants[variantIndex].options.length !== 0){
            const options = variants[variantIndex].options;
            const lastOptionId = options[options.length - 1].id || 0;
            variants[variantIndex].options.push({
                id : lastOptionId + 1,
                name : optionName,
                values : optionValues
            });            
        }else variants[variantIndex].options = [{
            id : 1,
            name : optionName,
            values : optionValues
        }]
        this.setState({variants});
    }
    newVariantContinueBtnHandler(){
        const {newVariantName} = this.state;
        if(!newVariantName || newVariantName === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field")
            )(this.props.dispatch);
            return;
        }
        this.addNewVariant(newVariantName);
        this.setState({newVariantDialog : false});
    }
    addNewVariant(name){
        let {variants} = this.state;
        variants = variants ? [...variants] : [];
        const lastVariantIndex = variants[variants.length - 1].id || 0;
        variants.push({
            _id : lastVariantIndex + 1,
            name
        })
        this.setState({variants});
    }
    newVariantOnChange(e){
        const value = e.target.value;
        this.setState({newVariantName : value});
    }
    render() {
        const {classes} = this.props;
        let { variants, newVariantDialog, newVariantName} = this.state;
        let header = ["Names", "Values", "Actions"];
        let dataMap = ["name", "values", "action"];
        
        return (
            <div className={classes.root}>
                <div className={classes.newVariant}>
                    <Button 
                        onClick={()=>this.setState({newVariantDialog: true})}
                        style={{backgroundColor : colors.secondary, color : colors.white}}>
                        New Category
                    </Button>
                </div>
                <MyDialog 
                    open={newVariantDialog}>
                    <FormLabel>New Variant Category</FormLabel>
                    <FormControl>
                        <TextField
                            label="Variant Category Name"
                            placeholder="Name"
                            margin="normal"
                            value={newVariantName}
                            onChange={e=>this.newVariantOnChange(e)}/>
                    </FormControl>
                    <FormControl style={{flexDirection: "row"}}>
                            <Button 
                                style={{margin: 5}}
                                variant="outlined"
                                color="secondary" 
                                onClick={()=>this.setState({newVariantDialog: false})}>
                                    Cancel
                            </Button>
                            <Button 
                                style={{margin: 5}}
                                variant="outlined"
                                color="primary" 
                                onClick={()=>this.newVariantContinueBtnHandler()}>
                                    Continue
                            </Button>
                    </FormControl>
                </MyDialog>
                {variants && variants.map((item, index)=>{ 
                    let {options} = item;
                    options = options ? [...options] : []; 
                        options = options ?
                        [...options.map(
                            item=>({...item, editable : true, delible :true})
                        ), {new : true}] : 
                        [{new : true}];
                    return <ExpansionPanel expanded={true} key={index}>
                        <ExpansionPanelSummary>
                            {item.name}
                        </ExpansionPanelSummary>
                        <ExpansionPanelDetails style={{
                            backgroundColor : colors.gainsboro,
                            padding : 0,
                        }}>
                            <MyTable
                                elevation={0}
                                header={header}
                                dataMap={dataMap}
                                data={options}
                                CellMap={this.cellMapFormat({
                                    addButtonHandler : this.addButtonHandler(index),
                                    tableCellContentView : this.tableCellContentView(index),
                                    editBtnHandler : this.editBtnHandler(index),
                                    cancelEditBtnHandler : this.cancelEditBtnHandler(index),
                                    deleteBtnHandler : this.deleteBtnHandler(index),
                                })}
                                />
                        </ExpansionPanelDetails>
                    </ExpansionPanel>
                

                })}
            </div>
        );
    }
}


_ItemVariants.propTypes = {
    classes : PropTypes.object.isRequired,
    variants : PropTypes.array,
};



export const ItemVariants = connect()(withStyles(style)(_ItemVariants));
export {ItemVariants as default}