import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardHeader, Button, Popover, ListItem, List, CardContent, Table, TableBody, Typography, IconButton } from '@material-ui/core';
import DescriptionRow from './DescriptionRow';
import { Add } from '@material-ui/icons';
import { colors } from '../../../../../../../utils';


const style = theme => ({
    root: {
        marginTop : 20,
    },
    grow : {
        display : 'flex',
        flexGrow : 1,
    }
})
class _Description extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null,
            descriptionSetup : {},
        }
        this.rowContexes = [];
        const {getContext} = props;
        if(getContext) getContext(this);
    }    
    showDescriptionPopover = (e) => {
        const target = e.currentTarget;
        this.setState(({anchorEl})=>({anchorEl : anchorEl ? null : target}));
    }
    getDescriptionNames(descriptions){
        let names = [];
        if(descriptions) for (let i = 0; i < descriptions.length; i++) {
            const desc = descriptions[i];
            names.push({_id : desc._id, name : desc.name});
        }
        return names;
    }
    selectDescriptionType = _id => () => {
        let descriptionSetup = {...this.state.descriptionSetup};
        if(descriptionSetup[_id]) descriptionSetup[_id].push({});
        else descriptionSetup[_id] = [{}];
        this.setState({descriptionSetup, anchorEl: null});
    }
    descriptionOptionCentext = descriptionId => context => {
        if(this.rowContexes[descriptionId])
            this.rowContexes[descriptionId].push(context);
        else this.rowContexes = [context];
    }
    deleteRow = (_id, optionIndex) => () => {
        let descriptionSetup = {...this.state.descriptionSetup};
        if(descriptionSetup[_id]) 
            descriptionSetup[_id].splice(optionIndex, 1);
        this.setState({descriptionSetup});
    }
    render() {
        const {
            classes,
            descriptions, title
        } = this.props;
        const {anchorEl, descriptionSetup} = this.state;
        return (
            <div className={classes.root}>
                <Card elevation={this.props.elevation}>
                    <CardHeader
                        title={<div style={{display : "flex"}}>
                            <Typography variant="h6">{title}</Typography>
                            <div className={classes.grow}/>
                            <IconButton onClick={this.showDescriptionPopover.bind(this)}>
                                <Add style={{color : colors.secondary}}/>
                            </IconButton>
                            <Popover 
                                anchorOrigin={{
                                    horizontal : "right",
                                    vertical : "top"
                                }}
                                transformOrigin={{
                                    horizontal : "right",
                                    vertical : "top"
                                }}
                                open={Boolean(anchorEl)}
                                anchorEl={anchorEl}
                                onClose={()=>this.setState({anchorEl: null})}>
                                    <List style={{maxHeight : "5cm", overflow : "scroll"}}>
                                        {descriptions && this.getDescriptionNames(descriptions).map((item, index)=>{

                                            return <ListItem 
                                                key={index} 
                                                button 
                                                onClick={this.selectDescriptionType(item._id)}>
                                                {item.name}
                                            </ListItem>
                                        })}
                                    </List>
                                </Popover>
                        </div>}/>
                        <CardContent
                             style={{maxHeight : "5cm", overflow : "scroll"}}>
                            {Object.entries(descriptionSetup).map((item, index)=>{ 
                                const descriptionId = parseInt(item[0]);
                                const descriptionValues = item[1];
                                const {item : descriptionItem, index : descriptionIndex} = descriptions.getFirstObjectByPropValue("_id", descriptionId);
                                if(descriptionItem){

                                    return <div key={item[0]+""+index}>
                                        <strong>{descriptionItem.name}</strong>
                                        <Table>
                                            <TableBody>
                                                {descriptionValues && descriptionValues.map((optionItem, optionIndex)=>{

                                                    return <DescriptionRow key={optionIndex}
                                                        descriptionId={descriptionId}
                                                        getContext={this.descriptionOptionCentext(descriptionId)}
                                                        deleteRow={this.deleteRow(descriptionId, optionIndex)}/>
                                                })}
                                            </TableBody>
                                        </Table>
                                    </div>;
                                }
                            })}
                        </CardContent>
                </Card>
            </div>
        );
    }
}


_Description.propTypes = {
    classes : PropTypes.object.isRequired,
    descriptions : PropTypes.array,
    elevation : PropTypes.number,
    getContext : PropTypes.func,
};



export const Description = withStyles(style)(_Description);
export {Description as default}