import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { CardHeader, Card, Button, Typography, FormControl, FormLabel, TextField, IconButton, CardContent, Table, TableRow, TableCell, TableBody, Grid } from '@material-ui/core';
import { MyDialog } from '../../../../../../includes';
import Description from '../Description/Description';
import { Add, Close } from '@material-ui/icons';
import { colors } from '../../../../../../../utils';
import { appReducer } from '../../../../../../../reducers';
import { appActions, alertAction } from '../../../../../../../actions';
const style = theme => ({
    root: {
        marginTop : 20
    },
    grow : {
        display : "flex",
        flexGrow : 1
    },
    btn : {
        margin : 10
    }
})
class _Variants extends Component {
    constructor(props) {
        super(props);
        this.state = {
            nameDialog : false,
            setupDialog : false,
            variants : [
            ],
            data : {
                name : ""
            }
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    onNameChange = e => {
        const value = e.target.value;
        let data = {...this.state.data};
        data.name = value;
        this.setState({data});
    }
    moveToVariantConfiguration = ()=>{
        const {name} = this.state.data;
        if(!name || name.trim() === ""){
            appActions.showSnackbar(
                alertAction.error("Name is empty!!!")
            )(this.props.dispatch);
            return;
        }
        this.setState({nameDialog: false, setupDialog : true})
    }
    createVariant = ()=>{
        const {name} = this.state.data;
        let {variants} = this.state;
        variants = variants ? [...variants] : [];
        const {rowContexes} = this.varaintContext;
        let data = null;
        let options = [];
        if(rowContexes) for (let i = 0; i < rowContexes.length; i++) {
            const context = rowContexes[i];
            const {descriptionId : variantId} = context.props;
            if(!data) data = {
                variantId,
                name
            }
            const { selectedOptionId : optionId, selectedOptionValueId : valueId} = context.state;
            options.push({
                optionId : optionId,
                valueId : valueId,
            });
        }
        if(data){
            data.options = options;
            variants.push(data);
            this.setState({variants, setupDialog : false, name : ""});
        }else appActions.showSnackbar(
            alertAction.error("No variant option added")
        )(this.props.dispatch);
    }
    getRandomColor(){
        const colors = ["red", "#7d7dbd", "gray", "green", "brown"];
        return colors[Math.floor((Math.random()  * colors.length))]
    }
    deleteSelectedVariant = variantIndex => () => {
        let {variants} = this.state;
        variants = variants ? [...variants] : [];
        variants.splice(variantIndex, 1);
        this.setState({variants});
    }
    render() {
        const {classes, title, variants} = this.props;
        const {nameDialog, setupDialog, data, variants : selectedVariants} = this.state;
        // let selectedVariants = [
        //     {
        //         variantId : 1,
        //         name : "Black",
        //         options : [
        //             {optionId : 1, valueId : 1}
        //         ]
        //     }
        // ]
        
        return (
            <div className={classes.root}>
                <Card>
                    <CardHeader
                        title={<div style={{display : "flex"}}>
                            <Typography variant="h6">{title}</Typography>
                            <div className={classes.grow}/>
                            <IconButton onClick={()=>this.setState({nameDialog : true})}>
                                <Add style={{color : colors.secondary}}/>
                            </IconButton>
                        </div>}
                        />
                    <CardContent>
                        <Grid container spacing={2}>
                            {selectedVariants && selectedVariants.map((item, index)=>{
                                const {variantId, options, name} = item;
                                const {item : variantCategory} =
                                    variants.getFirstObjectByPropValue("_id", variantId) || {};
                                return <Grid key={index} item xs={6} sm={4} md={4} lg={3} xl={3}>
                                    <Card 
                                        style={{backgroundColor : this.getRandomColor(), color : colors.white}}
                                        elevation={0}
                                        color="secondary">
                                        <CardHeader title={
                                            <div style={{display:"flex"}}>
                                                {name}
                                                <div style={{display : "flex", flexGrow :1}}/>
                                                <IconButton onClick={this.deleteSelectedVariant(index)}>
                                                    <Close color="secondary"/>
                                                </IconButton>
                                            </div>}
                                            />
                                        <CardContent>
                                            <Table>
                                                <TableBody>
                                                    <TableRow>
                                                        <TableCell colSpan={2}>
                                                            {variantCategory && variantCategory.name}
                                                        </TableCell>
                                                    </TableRow>
                                                    {options.map((optionItem, optionIndex)=>{
                                                        const {optionId, valueId} = optionItem;
                                                        const {item : _optionItem} = variantCategory.options.getFirstObjectByPropValue("_id", optionId);
                                                        const {item : _valueItem} = _optionItem.values.getFirstObjectByPropValue("_id", valueId);
                                                        return <TableRow key={optionIndex}>
                                                            <TableCell>{_optionItem.name}</TableCell>
                                                            <TableCell>{_valueItem.name}</TableCell>
                                                        </TableRow>
                                                    })}
                                                </TableBody>
                                            </Table>
                                        </CardContent>
                                    </Card>
                                </Grid>
                            })}
                        </Grid>
                    </CardContent>
                </Card>
                <MyDialog open={nameDialog}>
                    <FormLabel>Variants</FormLabel>
                    <FormControl>
                        <TextField
                            value={data.name}
                            label="Varaint Name"
                            placeholder="Variant name"
                            onChange={this.onNameChange.bind(this)}
                            margin="normal"/>
                    </FormControl>
                    <FormControl style={{display : "flex", flexDirection : "row"}}>
                        <Button
                            variant="outlined"
                            className={classes.btn}
                            color="secondary"
                            onClick={()=>this.setState({nameDialog: false})}>
                                Cancel
                            </Button>
                        <Button
                            variant="outlined"
                            className={classes.btn}
                            color="primary"
                            onClick={()=>this.moveToVariantConfiguration()}>
                                Continue
                            </Button>
                    </FormControl>
                </MyDialog>
                <MyDialog open={setupDialog}>
                    <Description
                        elevation={0}
                        title={"Variants - " + data.name}
                        descriptions={variants}
                        getContext={context => this.varaintContext = context}/>
                    <FormControl style={{display : "flex", flexDirection : "row"}}>
                        <Button
                            variant="outlined"
                            className={classes.btn}
                            color="secondary"
                            onClick={()=>this.setState({nameDialog: true, setupDialog :false})}>
                                Back
                            </Button>
                        <Button
                            variant="outlined"
                            className={classes.btn}
                            color="primary"
                            onClick={()=>this.createVariant()}>
                                Create Variant
                            </Button>
                    </FormControl>
                </MyDialog>
            </div>
        );
    }
}
_Variants.propTypes = {
    classes : PropTypes.object.isRequired,
    title : PropTypes.string,
    variants : PropTypes.array,
    getContext : PropTypes.func,
    formContext : PropTypes.any,
};
export const Variants = connect()(withStyles(style)(_Variants));